const payload = $json.body || $json;
const now = new Date();
const rand = Math.random().toString(36).slice(2, 6).toUpperCase();
const providedIngestionId = typeof payload.ingestion_id === 'string' ? payload.ingestion_id.trim() : '';
const ingestion_id = providedIngestionId || ('SIGA-ING-' + now.getUTCFullYear() + String(now.getUTCMonth()+1).padStart(2,'0') + String(now.getUTCDate()).padStart(2,'0') + '-' + String(now.getUTCHours()).padStart(2,'0') + String(now.getUTCMinutes()).padStart(2,'0') + String(now.getUTCSeconds()).padStart(2,'0') + '-' + String(now.getUTCMilliseconds()).padStart(3,'0') + '-' + rand);

const readEnv = (name) => {
  try {
    if (typeof process !== 'undefined' && process?.env && typeof process.env[name] === 'string') {
      const v = process.env[name].trim();
      if (v) return v;
    }
  } catch {}
  return '';
};
const configuredSecret = [
  'SIGA_WEBHOOK_SECRET', 'SIGA_SHARED_SECRET',
  'N8N_SIGA_WEBHOOK_SECRET', 'N8N_SIGA_SHARED_SECRET'
].map(readEnv).find(Boolean) || '';
const headerSecret = $json.headers?.['x-siga-shared-secret'] || $json.headers?.['X-SIGA-SHARED-SECRET'] || null;
const authHeader = $json.headers?.authorization || $json.headers?.Authorization || null;
const bearerToken = typeof authHeader === 'string' ? authHeader.replace(/^Bearer\s+/i, '').trim() : '';
const authConfigured = !!configuredSecret;
const authPassed = !authConfigured || headerSecret === configuredSecret || bearerToken === configuredSecret;

// --- Build images array from multipart binary fields (image_upload0, image_upload1, ...) ---
const binaryFields = Object.keys($binary || {})
  .filter(k => k.startsWith('image_upload'))
  .sort((a, b) => {
    const ia = parseInt(a.replace('image_upload', ''), 10) || 0;
    const ib = parseInt(b.replace('image_upload', ''), 10) || 0;
    return ia - ib;
  });

const normalizedImages = binaryFields.map((key, idx) => {
  const bin = $binary[key] || {};
  return {
    index: idx + 1,
    filename: bin.fileName || bin.filename || ('image_' + (idx + 1) + '.jpg'),
    mime_type: bin.mimeType || 'image/jpeg',
    content_base64: bin.data || null,  // may be null in filesystem binary mode
    binary_key: key                    // reference to $binary field for downstream use
  };
});

// Fallback: legacy JSON payload with content_base64
const legacyImages = normalizedImages.length === 0 && Array.isArray(payload.images)
  ? payload.images.map((img, idx) => ({
      index: Number(img.index || idx + 1),
      filename: img.filename || ('image_' + (idx + 1) + '.jpg'),
      mime_type: img.mime_type || 'image/jpeg',
      content_base64: img.content_base64 || null,
      binary_key: null
    }))
  : [];

const images = normalizedImages.length > 0 ? normalizedImages : legacyImages;
const validImageCount = images.filter(img => !!img.content_base64 || !!img.binary_key).length;

const errors = [];
if (images.length === 0) errors.push({ code: 'no_images', message: 'At least one image is required' });
if (!authPassed) errors.push({ code: 'unauthorized', message: 'Invalid shared secret' });

const messageText = typeof payload.message === 'string'
  ? payload.message
  : (payload.message?.text || payload.message_text || '');
const sender = payload.sender || {};

return [{ json: {
  ok: errors.length === 0,
  stage: errors.length === 0 ? 'accepted' : 'rejected',
  error: errors.length ? errors[0].message : null,
  errors,
  auth: {
    configured: authConfigured,
    passed: authPassed,
    mode: authConfigured ? 'server_secret_enforced' : 'open_unconfigured',
    accepted_via: !authConfigured ? 'open_unconfigured' : (headerSecret === configuredSecret ? 'x-siga-shared-secret' : (bearerToken === configuredSecret ? 'authorization_bearer' : 'rejected')),
    secret_source: authConfigured ? 'server_env' : 'not_configured'
  },
  project: payload.project || 'SIGA',
  entity_type: payload.entity_type || 'equipment',
  source: payload.source || (binaryFields.length > 0 ? 'mobile_app' : 'whatsapp'),
  ingestion_id,
  sender: { id: sender.id || null, display_name: sender.display_name || null },
  message: {
    id: payload.message_id || payload.message?.id || null,
    text: messageText,
    received_at: payload.message?.received_at || now.toISOString()
  },
  images,
  image_count: images.length,
  valid_image_count: validImageCount,
  context: payload.context || {},
  raw_payload: payload
} }];

