import duckdb, json, time, gc
from contextlib import contextmanager
DB_PATH = '/files/duckdb/siga_v1.duckdb'
@contextmanager
def db_con(path=DB_PATH, retries=5, delay=0.3):
    con = None
    for attempt in range(retries):
        try:
            con = duckdb.connect(path)
            break
        except Exception as e:
            if 'lock' in str(e).lower() and attempt < retries - 1:
                time.sleep(delay * (2 ** attempt))
            else:
                raise
    try:
        yield con
    finally:
        if con is not None:
            try: con.close()
            except Exception: pass
        gc.collect()
out=[]
with db_con() as con:
    for it in _items:
        d = it.get('json', {}) or {}
        sender = d.get('sender', {}) or {}
        message = d.get('message', {}) or {}
        con.execute("INSERT OR REPLACE INTO equipment_ingestion_log (ingestion_id, project, entity_type, source_channel, source_sender_id, source_sender_name, source_message_id, source_message_text, received_at, image_count, raw_payload_json, processing_status, review_required, error_json, updated_at) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, CURRENT_TIMESTAMP)", [d.get('ingestion_id'), d.get('project'), d.get('entity_type','equipment'), d.get('source'), sender.get('id'), sender.get('display_name'), message.get('id'), message.get('text'), message.get('received_at'), d.get('image_count', 0), json.dumps(d.get('raw_payload', {}), ensure_ascii=False), 'received', True, json.dumps(d.get('errors', []), ensure_ascii=False) if d.get('errors') else None])
        out.append({'json': d})
return out

